const lines = input.split('\n');
const out = [];
let indent = 0;
for (const raw of lines) {
  const line = raw.trim();
  if (!line) { if (out.length && out[out.length-1] !== '') out.push(''); continue; }
  // Decrease indent before closing brace
  if (line.startsWith('}')) indent = Math.max(0, indent - 1);
  // Normalize spaces around '='
  let formatted = line.replace(/\s*=\s*/g, ' = ');
  // Normalize spaces after ':'
  formatted = formatted.replace(/:\s+/g, ': ');
  out.push('  '.repeat(indent) + formatted);
  // Increase indent after opening brace
  if (line.endsWith('{')) indent++;
}
// Remove consecutive blank lines
const result = out.join('\n').replace(/\n{3,}/g, '\n\n');
return { output: result + '\n', outputLanguage: 'protobuf' };
